// src/components/Sponsors.jsx
import './Sponsors.css';



const tiers = [
  {
    tier: 'Gold', cls: 'gold', badge: '⭐ Gold Partner', price: '₹2L',
    desc: 'Top-tier visibility and exclusive privileges throughout the entire event.',
    perks: ['Prime logo placement on stage & website', 'Dedicated sponsor booth (10×10 ft)', 'Speaking slot at opening ceremony', 'Full access to participant resumes', 'Social media feature campaign', 'Sponsor a custom challenge track'],
  },
  {
    tier: 'Silver', cls: 'silver', badge: '🥈 Silver Partner', price: '₹1L',
    desc: 'Strong brand presence with meaningful engagement opportunities.',
    perks: ['Logo on website and printed materials', 'Shared sponsor booth space', 'Brand mention in all announcements', 'Social media shoutouts (3 posts)', 'Access to participant portfolio links'],
  },
  {
    tier: 'Bronze', cls: 'bronze', badge: '🥉 Bronze Partner', price: '₹50K',
    desc: 'Solid brand exposure for emerging companies and startups.',
    perks: ['Logo on event website', 'Social media mention at event', 'Digital banner at venue', '1 social media post feature'],
  },
];

const placeholderLogos = ['TechCorp India', 'InnovateLabs', 'DevBridge', 'AIFoundry', 'CodeNation', 'Your Brand Here'];

export default function Sponsors() {
  return (
    <section id="sponsors" className="sponsors-section">
      <p className="section-tag">Partnership</p>
      <h2 className="section-title">
        Advertise & <span className="gradient-text">Sponsor</span>
      </h2>
      <p className="section-desc">
        Join India's most exciting AI hackathon as a partner. Reach 500+ talented
        developers, designers, and innovators all in one room.
      </p>

      {/* Why sponsor */}
      <div className="why-grid fade-in">
        {whyCards.map(({ icon, title, desc }) => (
          <div className="why-card card" key={title}>
            <div className="why-icon">{icon}</div>
            <h4>{title}</h4>
            <p>{desc}</p>
          </div>
        ))}
      </div>

      {/* Tiers */}
      <h3 className="tiers-heading">Sponsorship <span className="gradient-text">Tiers</span></h3>
      <div className="tiers-grid fade-in">
        {tiers.map(({ tier, cls, badge, price, desc, perks }) => (
          <div className={`tier-card tier-card--${cls}`} key={tier}>
            <span className={`tier-badge tier-badge--${cls}`}>{badge}</span>
            <div className={`tier-price tier-price--${cls}`}>{price}</div>
            <p className="tier-desc">{desc}</p>
            <ul className="tier-perks">
              {perks.map((p) => <li className={`perk--${cls}`} key={p}>{p}</li>)}
            </ul>
            <button className={`tier-btn tier-btn--${cls}`}>
              Become {tier} Partner
            </button>
          </div>
        ))}
      </div>

      {/* Placeholder logos */}
      <p className="current-sponsors-label">Current Partners</p>
      <div className="sponsor-logos">
        {placeholderLogos.map((l) => (
          <div className="sponsor-logo-box" key={l}>{l}</div>
        ))}
      </div>
    </section>
  );
}
